struct Row {
    name: String,
    size: u64,
    modified: String,
}

fn print_table(rows: &[Row]) {
    let name_width = rows.iter().map(|r| r.name.len()).max().unwrap_or(4).max(4);

    println!("{:<width$}  {:>10}  {}",
        "Name", "Size", "Modified", width = name_width);
    println!("{}", "-".repeat(name_width + 24));

    for row in rows {
        println!("{:<width$}  {:>10}  {}",
            row.name, format_size(row.size), row.modified,
            width = name_width);
    }
}

fn format_size(bytes: u64) -> String {
    if bytes < 1024 {
        format!("{} B", bytes)
    } else if bytes < 1024 * 1024 {
        format!("{:.1} KB", bytes as f64 / 1024.0)
    } else {
        format!("{:.1} MB", bytes as f64 / (1024.0 * 1024.0))
    }
}

use serde::Serialize;

#[derive(Serialize)]
struct Output {
    files: Vec<FileInfo>,
    total_size: u64,
}

#[derive(Serialize)]
struct FileInfo {
    path: String,
    size: u64,
}

fn output_json(data: &Output) -> anyhow::Result<()> {
    let json = serde_json::to_string_pretty(data)?;
    println!("{}", json);
    Ok(())
}

use std::io::{self, Write};

fn process_with_progress(items: &[String]) {
    let total = items.len();
    for (i, item) in items.iter().enumerate() {
        // Progress to stderr (visible even when stdout is piped)
        eprint!("\rProcessing {}/{}...", i + 1, total);
        io::stderr().flush().unwrap();

        // Actual output to stdout
        println!("{}", item.to_uppercase());
    }
    eprintln!("\rDone! Processed {} items.", total);
}

use std::io::IsTerminal;

fn format_entry(name: &str, status: &str) -> String {
    if std::io::stdout().is_terminal() {
        // Terminal: use formatting
        format!("  * {} -- {}", name, status)
    } else {
        // Pipe: plain tab-separated
        format!("{}\t{}", name, status)
    }
}
